<template>
  <aside v-if="open" class="expense-anomaly-drawer" role="dialog" aria-modal="true" aria-labelledby="expense-anomaly-drawer-title">
    <header class="drawer-header"><h2 id="expense-anomaly-drawer-title">异常监控详情</h2><button type="button" aria-label="关闭异常监控详情" @click="emit('close')">×</button></header>
    <div class="drawer-body">
      <section><h3>基本信息</h3><dl class="info-grid"><div><dt>异常编号</dt><dd>{{ displayAnomalyId }}</dd></div><div><dt>异常类型</dt><dd>{{ row.type }}</dd></div><div><dt>风险等级</dt><dd><span class="risk-chip" :class="riskClass(row.riskLevel)">{{ row.riskLevel }}风险</span></dd></div><div><dt>部门</dt><dd>{{ row.department }}</dd></div><div><dt>员工</dt><dd>{{ row.employee }}（工号：{{ row.employeeNo }}）</dd></div><div><dt>发生日期</dt><dd>{{ row.occurredAt }}</dd></div><div><dt>金额（元）</dt><dd>{{ formatAmount(row.amount) }}</dd></div><div><dt>处理状态</dt><dd>{{ row.status }}</dd></div></dl></section>
      <section><h3>命中规则</h3><dl class="info-grid"><div><dt>规则名称</dt><dd>{{ row.ruleName || row.type }}</dd></div><div><dt>规则版本</dt><dd>{{ row.ruleId || 'V2.1' }}</dd></div><div><dt>规则说明</dt><dd>{{ ruleDescription }}</dd></div></dl></section>
      <section><h3>证据链路（{{ evidenceFiles.length }}）</h3><ul class="evidence-list"><li v-for="file in evidenceFiles" :key="file.name || file"><i :class="file.type || 'pdf'">{{ file.type || 'PDF' }}</i><span>{{ file.name || file }}</span></li></ul></section>
      <section><h3>审批链路</h3><ol v-if="approvalSteps.length" class="approval-timeline"><li v-for="(item, index) in approvalSteps" :key="`${approvalLabel(item)}-${index}`" :class="{ active: index === 1, muted: index > 2 }"><i></i><div><strong>{{ approvalLabel(item) }}</strong><span>{{ approvalActor(item) }}　{{ item.time || '' }}</span><small v-if="item.note">{{ item.note }}</small></div></li></ol><p v-else class="empty">暂无审批链路</p></section>
      <section><h3>相似记录（{{ similarRecords.length }}）</h3><ul class="similar-list"><li v-for="item in similarRecords" :key="similarId(item)"><span>{{ similarId(item) }}</span><small v-if="similarAmount(item)">{{ similarDate(item) }}　￥{{ formatAmount(similarAmount(item)) }}</small><b v-if="similarRisk(item)">{{ similarRisk(item) }}</b></li></ul></section>
      <section class="manual-section"><h3>人工处理</h3><label for="expense-exclusion-reason">排除原因</label><textarea id="expense-exclusion-reason" v-model="exclusionReasonDraft" rows="2" placeholder="排除异常时必填"></textarea><label for="expense-supplement-note">补充说明</label><textarea id="expense-supplement-note" v-model="supplementDraft" rows="2" placeholder="填写需要补充的处理说明"></textarea><p v-if="row.supplementNote" class="existing-note">已有说明：{{ row.supplementNote }}</p><p v-if="formError" class="form-error" role="alert">{{ formError }}</p></section>
    </div>
    <footer class="drawer-footer"><button class="primary" type="button" :disabled="isTerminal" @click="confirm">确认异常</button><button type="button" :disabled="isTerminal" @click="excludeAnomaly">排除异常</button><button type="button" @click="saveSupplement">补充说明</button></footer>
  </aside>
</template>

<script setup>
import { computed, ref, watch } from 'vue';

const props = defineProps({ row:{type:Object,required:true}, evidence:{type:Object,default:null}, open:{type:Boolean,required:true} });
const emit = defineEmits(['close', 'confirm', 'exclude', 'save-supplement']);
const exclusionReasonDraft = ref('');
const supplementDraft = ref('');
const formError = ref('');
const safeEvidence = computed(() => props.evidence?.anomalyId === props.row?.anomalyId ? props.evidence : {});
const evidenceFiles = computed(() => safeEvidence.value.evidenceFiles || [{ name:'费用报销单_001245.pdf', type:'pdf' }, { name:'预算控制表_202503.xlsx', type:'xls' }, { name:'超预算对比报告_202503.pdf', type:'pdf' }]);
const approvalSteps = computed(() => safeEvidence.value.approvalSteps || [{ action:'提交申请', actor:props.row.employee, time:'2025-03-15 09:12' }, { action:'部门经理审批', actor:'李强', time:'2025-03-15 10:05', note:'驳回原因：超预算未说明' }, { action:'重新提交', actor:props.row.employee, time:'2025-03-15 10:20' }, { action:'未走完审批流程', actor:'系统', time:'' }]);
const similarRecords = computed(() => safeEvidence.value.similarRecords || [{ id:'FY-202503120045', date:'2025-03-12', amount:21350, riskLevel:'高' }, { id:'FY-202503050022', date:'2025-03-05', amount:18600, riskLevel:'高' }]);
const isTerminal = computed(() => props.row?.status === '已确认' || props.row?.status === '已排除');
const displayAnomalyId = computed(() => props.row.displayId || props.row.auditNo || props.row.anomalyCode || props.row.anomalyId);
const ruleDescription = computed(() => safeEvidence.value.ruleHit || `${props.row.type}，需结合预算、审批和凭证一致性复核。`);
watch(() => props.row, (row) => { exclusionReasonDraft.value = row?.exclusionReason || ''; supplementDraft.value = ''; formError.value = ''; }, { immediate:true });
function confirm(){ formError.value=''; emit('confirm', props.row); }
function excludeAnomaly(){ const reason = exclusionReasonDraft.value.trim(); if(!reason){ formError.value='请输入排除原因'; return; } formError.value=''; emit('exclude', props.row, reason); }
function saveSupplement(){ const note = supplementDraft.value.trim(); if(!note){ formError.value='请输入补充说明'; return; } formError.value=''; emit('save-supplement', props.row, note); }
function riskClass(riskLevel){ return { 高:'high', 中:'medium', 低:'low' }[riskLevel] || 'medium'; }
function formatAmount(amount){ return Number(amount || 0).toLocaleString('zh-CN', { minimumFractionDigits:2, maximumFractionDigits:2 }); }
function approvalLabel(item){ return typeof item === 'string' ? item : item.action || item.label || '审批节点'; }
function approvalActor(item){ return typeof item === 'string' ? '系统' : item.actor || item.person || '系统'; }
function similarId(item){ return typeof item === 'string' ? item : item.id || item.anomalyId || '相似记录'; }
function similarDate(item){ return typeof item === 'string' ? '' : item.date || ''; }
function similarAmount(item){ return typeof item === 'string' ? 0 : item.amount || 0; }
function similarRisk(item){ return typeof item === 'string' ? '' : item.riskLevel || ''; }
</script>

<style scoped>
.expense-anomaly-drawer{position:sticky;top:0;display:grid;grid-template-rows:auto minmax(0,1fr) auto;width:320px;height:100%;min-height:0;align-self:stretch;border-left:1px solid #dfe5ec;background:#fff;color:#1f2937}.drawer-header{display:flex;min-height:56px;align-items:center;justify-content:space-between;padding:0 16px;border-bottom:1px solid #e5e9ef}.drawer-header h2{font-size:15px;font-weight:800}.drawer-header button{border:0;background:transparent;color:#303846;font-size:24px}.drawer-body{min-height:0;overflow:auto;padding:0 14px 12px}section{padding:15px 0;border-bottom:1px solid #edf0f4}section:last-child{border-bottom:0}h3{margin:0 0 12px;color:#111827;font-size:13px;font-weight:800}.info-grid{display:grid;gap:9px;margin:0}.info-grid div{display:grid;grid-template-columns:78px minmax(0,1fr);gap:8px}dt{color:#667085;font-size:12px}dd{min-width:0;margin:0;overflow-wrap:anywhere;color:#263548;font-size:12px}a,.link-button{color:var(--color-info)}.link-button{display:block;margin:8px 0 0 auto;border:0;background:transparent;font-size:12px}.risk-chip{display:inline-flex;border-radius:4px;padding:2px 7px;font-size:12px}.risk-chip.high{color:var(--color-primary);background:#fff0f0}.risk-chip.medium{color:var(--color-warning);background:#fff7e8}.risk-chip.low{color:#0f8f55;background:#ebf8f1}.evidence-list{display:grid;gap:8px;margin:0;padding:0;list-style:none;font-size:12px}.evidence-list li{display:grid;grid-template-columns:20px minmax(0,1fr);align-items:center;gap:8px}.evidence-list i{display:grid;width:18px;height:18px;place-items:center;border-radius:3px;background:var(--color-primary);color:#fff;font-size:8px;font-style:normal;text-transform:uppercase}.evidence-list i.xls{background:var(--color-success)}.evidence-list span{overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.approval-timeline{display:grid;gap:11px;margin:0;padding:0;list-style:none}.approval-timeline li{position:relative;display:grid;grid-template-columns:14px minmax(0,1fr);gap:8px;color:#667085}.approval-timeline i{width:8px;height:8px;margin-top:4px;border-radius:50%;background:#b6c0cc}.similar-list{display:grid;gap:7px;margin:0;padding-left:18px;color:#344054;font-size:12px}.similar-list li{display:grid;grid-template-columns:minmax(0,1fr) auto auto;align-items:center;gap:5px}.similar-list span{overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.similar-list small{color:#667085;white-space:nowrap}.similar-list b{border-radius:3px;padding:1px 4px;background:#fff0f0;color:var(--color-primary);font-size:11px;white-space:nowrap}.manual-section{display:grid;gap:7px}.manual-section label{color:#475467;font-size:12px}textarea{width:100%;resize:vertical;border:1px solid #cfd8e3;border-radius:4px;padding:7px 8px;color:#1f2937;font:inherit;font-size:12px}.existing-note{margin:0;color:#667085;font-size:12px}.form-error{margin:0;color:var(--color-primary);font-size:12px}.empty{margin:0;color:#98a2b3;font-size:12px}.drawer-footer{display:flex;gap:8px;padding:12px 14px;border-top:1px solid #dfe5ec;background:#fff}.drawer-footer button{height:32px;min-width:72px;border:1px solid #d6dde8;border-radius:4px;background:#fff;color:#344054;font-size:12px}.drawer-footer .primary{border-color:var(--color-primary);background:var(--color-primary);color:#fff;font-weight:700}.drawer-footer button:disabled{cursor:not-allowed;opacity:.48}@media(max-width:900px){.expense-anomaly-drawer{position:relative;top:auto;width:100%;height:auto}.drawer-body{overflow:visible}}@media(max-width:760px){.expense-anomaly-drawer{width:100%}}
</style>
